"use client";

import { useEffect, useMemo, useRef, useState } from "react";
import {
  DndContext, pointerWithin, closestCenter, PointerSensor, useSensor, useSensors,
  DragOverlay, type DragStartEvent, type DragOverEvent, type DragEndEvent, type CollisionDetection,
} from "@dnd-kit/core";
import { useFormBuilderState, findContainer } from "./builder-state";
import { FieldPalette } from "./field-palette";
import { BuilderCanvas } from "./canvas";
import { FieldConfigPanel } from "./field-config-panel";
import { FieldPreview } from "./field-preview";
import { cn } from "@/lib/utils";
import type { FormSchema, FieldType, FormFieldDefinition, CanvasField } from "../form-renderer/types";

export interface FormBuilderProps {
  catalog: FormFieldDefinition[];
  defaultSchema?: Partial<FormSchema>;
  onChange?: (schema: FormSchema) => void;
  className?: string;
}

export function FormBuilder({ catalog, defaultSchema, onChange, className }: FormBuilderProps) {
  const catalogMap = useMemo(
    () => Object.fromEntries(catalog.map((d) => [d.fieldType, d])),
    [catalog]
  );

  const {
    state, schema,
    addField, addGrid, removeItem,
    reorderItems, reorderFieldsInGrid, moveField,
    updateFieldProp, updateGridColumns,
    updateStackConfig, updateButtonConfig,
    selectField, setFormMeta,
    fullCatalogMap,
  } = useFormBuilderState(catalogMap, defaultSchema ? { fromSchema: defaultSchema } : undefined);

  const onChangeRef = useRef(onChange);
  onChangeRef.current = onChange;

  useEffect(() => {
    onChangeRef.current?.(schema);
  }, [schema]);

  const sensors = useSensors(useSensor(PointerSensor, { activationConstraint: { distance: 5 } }));

  // Use pointer-within as primary, sorted by rect area so the smallest (most specific)
  // droppable wins — e.g. a grid's inner zone beats the grid's sortable rect, which
  // beats the root canvas. Falls back to closestCenter when pointer is outside all rects.
  const collisionDetection: CollisionDetection = (args) => {
    const within = pointerWithin(args);
    if (within.length > 0) {
      return [...within].sort((a, b) => {
        const ra = args.droppableRects.get(a.id);
        const rb = args.droppableRects.get(b.id);
        if (!ra || !rb) return 0;
        return ra.width * ra.height - rb.width * rb.height;
      });
    }
    return closestCenter(args);
  };

  const [activeField, setActiveField] = useState<CanvasField | null>(null);
  const [activePaletteLabel, setActivePaletteLabel] = useState<string | null>(null);
  const [overContainerId, setOverContainerId] = useState<string | null>(null);
  const [dragItem, setDragItem] = useState<{ label: string; icon?: FormFieldDefinition["icon"]; isFromRoot?: boolean } | null>(null);

  function findField(fieldId: string): CanvasField | undefined {
    for (const item of state.items) {
      if (item.kind === "field" && item.id === fieldId) return item;
      if (item.kind === "grid") {
        const f = item.fields.find((f) => f.id === fieldId);
        if (f) return f;
      }
    }
  }

  function handleDragStart(event: DragStartEvent) {
    setOverContainerId(null);
    const data = event.active.data.current;

    if (data?.source === "palette") {
      if (data.kind === "grid") {
        const label = `${data.columns} Columns`;
        setActivePaletteLabel(label);
        setDragItem({ label });
      } else {
        const def = fullCatalogMap[data.fieldType as string];
        const label = def?.displayName ?? String(data.fieldType);
        setActivePaletteLabel(label);
        setDragItem({ label, icon: def?.icon });
      }
      return;
    }

    const id = String(event.active.id);
    const field = findField(id);
    if (field) {
      setActiveField(field);
      const def = fullCatalogMap[field.fieldType];
      const isFromRoot = state.items.some((i) => i.kind === "field" && i.id === id);
      setDragItem({
        label: (field.props.label as string) || field.fieldType,
        icon: def?.icon,
        isFromRoot,
      });
    }
  }

  function handleDragOver(event: DragOverEvent) {
    const { over } = event;
    if (!over) { setOverContainerId(null); return; }

    const overId = String(over.id);
    // Inner grid droppable → field would go into that grid
    if (overId.endsWith("-inner")) {
      setOverContainerId(overId.slice(0, -6));
      return;
    }
    // Grid sortable rect or field or root → resolve via findContainer
    // (grid as sortable item resolves to "root"; field in grid resolves to gridId)
    setOverContainerId(findContainer(state.items, overId));
  }

  function handleDragEnd(event: DragEndEvent) {
    const { active, over } = event;
    setActiveField(null);
    setActivePaletteLabel(null);
    setOverContainerId(null);
    setDragItem(null);

    const data = active.data.current;

    // ── Palette drop ──────────────────────────────────────────────────────────
    if (data?.source === "palette") {
      if (!over) return;
      const overId = String(over.id);

      if (data.kind === "grid") {
        addGrid(data.columns as 2 | 3);
        return;
      }

      const isInner = overId.endsWith("-inner");
      const targetGridId = isInner ? overId.slice(0, -6) : null;
      const overIsGrid = isInner && state.items.some((i) => i.kind === "grid" && i.id === targetGridId);
      addField(data.fieldType as string, overIsGrid ? targetGridId! : undefined);
      return;
    }

    // ── Canvas drop ───────────────────────────────────────────────────────────
    if (!over || active.id === over.id) return;

    const activeId = String(active.id);
    const overId = String(over.id);

    const fromContainer = findContainer(state.items, activeId);
    const isInner = overId.endsWith("-inner");
    const targetGridId = isInner ? overId.slice(0, -6) : null;
    const overIsGrid = !!targetGridId && state.items.some((i) => i.kind === "grid" && i.id === targetGridId);
    const toContainer = overIsGrid ? targetGridId! : findContainer(state.items, overId);

    if (fromContainer === toContainer) {
      // Same container — reorder (overId may be a grid id when sorting near it)
      if (fromContainer === "root") {
        reorderItems(activeId, overId);
      } else {
        reorderFieldsInGrid(fromContainer, activeId, overId);
      }
    } else {
      // Cross-container move — committed only on drop, no live moves during drag
      moveField(activeId, fromContainer, toContainer, overIsGrid ? undefined : overId);
    }
  }

  const selectedField =
    state.selectedFieldId
      ? (state.items
          .flatMap((i) => (i.kind === "grid" ? i.fields : [i as CanvasField]))
          .find((f) => f.id === state.selectedFieldId) ?? null)
      : null;

  return (
    <div className={cn("flex flex-col h-full w-full overflow-hidden", className)}>
      <header className="flex items-center gap-3 px-4 py-2.5 border-b border-border bg-background shrink-0">
        <input
          type="text"
          value={state.formTitle}
          onChange={(e) => setFormMeta("formTitle", e.target.value)}
          placeholder="Form title..."
          className="flex-1 bg-transparent text-sm font-medium focus:outline-none placeholder:text-muted-foreground"
        />
      </header>

      <div className="flex flex-1 overflow-hidden">
        <DndContext
          sensors={sensors}
          collisionDetection={collisionDetection}
          onDragStart={handleDragStart}
          onDragOver={handleDragOver}
          onDragEnd={handleDragEnd}
        >
          <FieldPalette
            catalog={catalog}
            onAddField={(ft: FieldType) => addField(ft)}
            onAddGrid={addGrid}
          />

          <BuilderCanvas
            items={state.items}
            selectedFieldId={state.selectedFieldId}
            formTitle={state.formTitle}
            catalogMap={fullCatalogMap}
            onSelectField={selectField}
            onRemoveItem={removeItem}
            onUpdateGridColumns={updateGridColumns}
            onClickCanvas={() => selectField(null)}
            isDragOver={overContainerId === "root"}
            dragItem={dragItem}
            draggingToGridId={
              activeField && dragItem?.isFromRoot && overContainerId && overContainerId !== "root"
                ? activeField.id
                : null
            }
          />

          <DragOverlay dropAnimation={null}>
            {activeField ? (
              <FieldPreview
                field={activeField}
                definition={fullCatalogMap[activeField.fieldType]}
                isSelected={false}
                onSelect={() => {}}
                onRemove={() => {}}
              />
            ) : activePaletteLabel ? (
              <div className="flex items-center gap-2 px-3 py-2 rounded-md border border-primary bg-background text-sm shadow-lg">
                {activePaletteLabel}
              </div>
            ) : null}
          </DragOverlay>
        </DndContext>

        <FieldConfigPanel
          field={selectedField}
          catalogMap={fullCatalogMap}
          onUpdateProp={updateFieldProp}
          stackConfig={state.stackConfig}
          buttonConfig={state.buttonConfig}
          onUpdateStackConfig={updateStackConfig}
          onUpdateButtonConfig={updateButtonConfig}
        />
      </div>
    </div>
  );
}

"use client";

import { useState, useCallback, useMemo } from "react";
import { buildSpecFromBuilderState, buildBuilderStateFromSpec, DEFAULT_STACK_CONFIG, DEFAULT_BUTTON_CONFIG } from "../shared/spec-builder";
import { BUILT_IN_LAYOUT_MAP } from "../shared/built-in-layout-defs";
import type {
  FormBuilderState,
  CanvasField,
  CanvasGrid,
  CanvasItem,
  FormSchema,
  FormFieldDefinition,
  StackConfig,
  ButtonConfig,
} from "../form-renderer/types";

function arrayMove<T>(arr: T[], from: number, to: number): T[] {
  const next = [...arr];
  const [item] = next.splice(from, 1);
  next.splice(to, 0, item);
  return next;
}

/** Find which container (root or grid id) holds the field with the given id. */
export function findContainer(items: CanvasItem[], fieldId: string): string {
  for (const item of items) {
    if (item.id === fieldId) return "root";
    if (item.kind === "grid" && item.fields.some((f) => f.id === fieldId)) return item.id;
  }
  return "root";
}

export function useFormBuilderState(
  catalogMap: Record<string, FormFieldDefinition>,
  initial?: Partial<FormBuilderState> | { fromSchema: Partial<FormSchema> }
) {
  const fullCatalogMap = useMemo(
    () => ({ ...BUILT_IN_LAYOUT_MAP, ...catalogMap }),
    [catalogMap]
  );
  const validFieldTypes = new Set(Object.keys(fullCatalogMap));

  const [state, setState] = useState<FormBuilderState>(() => {
    const base =
      initial && "fromSchema" in initial
        ? buildBuilderStateFromSpec(initial.fromSchema, validFieldTypes, fullCatalogMap)
        : initial;
    return {
      items: base?.items ?? [],
      selectedFieldId: null,
      formTitle: base?.formTitle ?? "My Form",
      formDescription: base?.formDescription ?? "",
      stackConfig: base?.stackConfig ?? { ...DEFAULT_STACK_CONFIG },
      buttonConfig: base?.buttonConfig ?? { ...DEFAULT_BUTTON_CONFIG },
    };
  });

  // ─── Add ──────────────────────────────────────────────────────────────────

  const addField = useCallback(
    (fieldType: string, gridId?: string) => {
      const def = fullCatalogMap[fieldType];
      if (!def) return;
      const id = crypto.randomUUID();
      const shortId = id.slice(0, 8);
      const elementKey = `field_${shortId}`;
      const baseProps = { ...def.defaultProps };
      if (!def.isStructural) {
        baseProps.name = `${fieldType.toLowerCase()}_${shortId}`;
      }
      const newField: CanvasField = { kind: "field", id, elementKey, fieldType, props: baseProps };

      setState((prev) => {
        if (gridId) {
          return {
            ...prev,
            items: prev.items.map((item) =>
              item.kind === "grid" && item.id === gridId
                ? { ...item, fields: [...item.fields, newField] }
                : item
            ),
            selectedFieldId: id,
          };
        }
        return { ...prev, items: [...prev.items, newField], selectedFieldId: id };
      });
    },
    [fullCatalogMap]
  );

  const addGrid = useCallback((columns: 2 | 3) => {
    const id = crypto.randomUUID();
    const shortId = id.slice(0, 8);
    const newGrid: CanvasGrid = { kind: "grid", id, elementKey: `grid_${shortId}`, columns, fields: [] };
    setState((prev) => ({ ...prev, items: [...prev.items, newGrid] }));
  }, []);

  // ─── Remove ───────────────────────────────────────────────────────────────

  const removeItem = useCallback((id: string) => {
    setState((prev) => {
      const items = prev.items
        .filter((item) => item.id !== id)
        .map((item): CanvasItem =>
          item.kind === "grid"
            ? { ...item, fields: item.fields.filter((f) => f.id !== id) }
            : item
        );
      return { ...prev, items, selectedFieldId: prev.selectedFieldId === id ? null : prev.selectedFieldId };
    });
  }, []);

  // ─── Reorder / move ───────────────────────────────────────────────────────

  const reorderItems = useCallback((activeId: string, overId: string) => {
    setState((prev) => {
      const from = prev.items.findIndex((i) => i.id === activeId);
      const to = prev.items.findIndex((i) => i.id === overId);
      if (from === -1 || to === -1 || from === to) return prev;
      return { ...prev, items: arrayMove(prev.items, from, to) };
    });
  }, []);

  const reorderFieldsInGrid = useCallback((gridId: string, activeId: string, overId: string) => {
    setState((prev) => ({
      ...prev,
      items: prev.items.map((item): CanvasItem => {
        if (item.kind !== "grid" || item.id !== gridId) return item;
        const from = item.fields.findIndex((f) => f.id === activeId);
        const to = item.fields.findIndex((f) => f.id === overId);
        if (from === -1 || to === -1 || from === to) return item;
        return { ...item, fields: arrayMove(item.fields, from, to) };
      }),
    }));
  }, []);

  const moveField = useCallback(
    (fieldId: string, fromContainer: string, toContainer: string, overId?: string) => {
      setState((prev) => {
        let movedField: CanvasField | undefined;

        let items = prev.items.map((item): CanvasItem => {
          if (fromContainer === "root" && item.kind === "field" && item.id === fieldId) {
            movedField = item;
            return item;
          }
          if (item.kind === "grid" && item.id === fromContainer) {
            const idx = item.fields.findIndex((f) => f.id === fieldId);
            if (idx !== -1) {
              movedField = item.fields[idx];
              return { ...item, fields: item.fields.filter((f) => f.id !== fieldId) };
            }
          }
          return item;
        });

        if (!movedField) return prev;
        if (fromContainer === "root") items = items.filter((item) => item.id !== fieldId);

        if (toContainer === "root") {
          const overIdx = overId ? items.findIndex((i) => i.id === overId) : -1;
          items = overIdx !== -1
            ? [...items.slice(0, overIdx), movedField, ...items.slice(overIdx)]
            : [...items, movedField];
        } else {
          items = items.map((item): CanvasItem => {
            if (item.kind !== "grid" || item.id !== toContainer) return item;
            const overIdx = overId ? item.fields.findIndex((f) => f.id === overId) : -1;
            const newFields = overIdx !== -1
              ? [...item.fields.slice(0, overIdx), movedField!, ...item.fields.slice(overIdx)]
              : [...item.fields, movedField!];
            return { ...item, fields: newFields };
          });
        }

        return { ...prev, items };
      });
    },
    []
  );

  // ─── Update ───────────────────────────────────────────────────────────────

  const updateFieldProp = useCallback((id: string, propKey: string, value: unknown) => {
    setState((prev) => ({
      ...prev,
      items: prev.items.map((item): CanvasItem => {
        if (item.kind === "field" && item.id === id) {
          return { ...item, props: { ...item.props, [propKey]: value } };
        }
        if (item.kind === "grid") {
          return { ...item, fields: item.fields.map((f) => f.id === id ? { ...f, props: { ...f.props, [propKey]: value } } : f) };
        }
        return item;
      }),
    }));
  }, []);

  const updateGridColumns = useCallback((gridId: string, columns: 2 | 3) => {
    setState((prev) => ({
      ...prev,
      items: prev.items.map((item) =>
        item.kind === "grid" && item.id === gridId ? { ...item, columns } : item
      ),
    }));
  }, []);

  const updateStackConfig = useCallback(<K extends keyof StackConfig>(key: K, value: StackConfig[K]) => {
    setState((prev) => ({ ...prev, stackConfig: { ...prev.stackConfig, [key]: value } }));
  }, []);

  const updateButtonConfig = useCallback(<K extends keyof ButtonConfig>(key: K, value: ButtonConfig[K]) => {
    setState((prev) => ({ ...prev, buttonConfig: { ...prev.buttonConfig, [key]: value } }));
  }, []);

  const selectField = useCallback((id: string | null) => {
    setState((prev) => ({ ...prev, selectedFieldId: id }));
  }, []);

  const setFormMeta = useCallback((key: "formTitle" | "formDescription", value: string) => {
    setState((prev) => ({ ...prev, [key]: value }));
  }, []);

  const schema = useMemo(
    () => buildSpecFromBuilderState(state, fullCatalogMap),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [state.items, state.formTitle, state.formDescription, state.stackConfig, state.buttonConfig]
  );

  return {
    state, schema,
    addField, addGrid, removeItem,
    reorderItems, reorderFieldsInGrid, moveField,
    updateFieldProp, updateGridColumns,
    updateStackConfig, updateButtonConfig,
    selectField, setFormMeta,
    fullCatalogMap,
  };
}

"use client";

import { SortableContext, verticalListSortingStrategy } from "@dnd-kit/sortable";
import { useDroppable } from "@dnd-kit/core";
import { useMemo } from "react";
import { LayoutGrid } from "lucide-react";
import { cn } from "@/lib/utils";
import { FieldPreview } from "./field-preview";
import { GridPreview } from "./grid-preview";
import type { CanvasItem, CanvasField, CanvasGrid, FormFieldDefinition } from "../form-renderer/types";

interface BuilderCanvasProps {
  items: CanvasItem[];
  selectedFieldId: string | null;
  formTitle: string;
  catalogMap: Record<string, FormFieldDefinition>;
  onSelectField: (id: string) => void;
  onRemoveItem: (id: string) => void;
  onUpdateGridColumns: (gridId: string, columns: 2 | 3) => void;
  onClickCanvas: () => void;
  isDragOver?: boolean;
  dragItem?: { label: string; icon?: FormFieldDefinition["icon"]; isFromRoot?: boolean } | null;
  /** Field id that is being dragged from root into a grid — hide its placeholder */
  draggingToGridId?: string | null;
}

export function BuilderCanvas({
  items, selectedFieldId, formTitle, catalogMap,
  onSelectField, onRemoveItem, onUpdateGridColumns, onClickCanvas,
  isDragOver, dragItem, draggingToGridId,
}: BuilderCanvasProps) {
  const { setNodeRef } = useDroppable({ id: "root" });
  const topLevelIds = useMemo(
    () => items.map((i) => i.id).filter((id) => id !== draggingToGridId),
    [items, draggingToGridId]
  );

  return (
    <main className="flex-1 overflow-y-auto bg-muted/10 p-6" onClick={onClickCanvas}>
      <div className="max-w-2xl mx-auto">
        <p className="text-lg font-semibold mb-4 text-center">{formTitle || "Untitled Form"}</p>
        <SortableContext items={topLevelIds} strategy={verticalListSortingStrategy}>
          <div
            ref={setNodeRef}
            className={cn(
              "flex flex-col gap-2 min-h-32 rounded-xl transition-colors p-4",
              isDragOver && "outline-dashed outline-2 outline-primary/50 bg-primary/5"
            )}
            onClick={(e) => e.stopPropagation()}
          >
            {items.length === 0 && !isDragOver ? (
              <div className="flex flex-col items-center justify-center gap-3 py-16 border-2 border-dashed border-border rounded-xl text-muted-foreground">
                <LayoutGrid className="h-8 w-8" />
                <p className="text-sm">Click a field from the left panel to add it</p>
              </div>
            ) : (
              <>
                {items.map((item) =>
                  item.kind === "grid" ? (
                    <GridPreview
                      key={item.id}
                      grid={item as CanvasGrid}
                      selectedFieldId={selectedFieldId}
                      catalogMap={catalogMap}
                      onSelectField={onSelectField}
                      onRemoveItem={onRemoveItem}
                      onUpdateColumns={onUpdateGridColumns}
                    />
                  ) : (
                    <FieldPreview
                      key={item.id}
                      field={item as CanvasField}
                      definition={catalogMap[item.fieldType]}
                      isSelected={selectedFieldId === item.id}
                      onSelect={onSelectField}
                      onRemove={onRemoveItem}
                      invisible={draggingToGridId === item.id}
                    />
                  )
                )}

                {isDragOver && dragItem && !dragItem.isFromRoot && (
                  <DropGhost label={dragItem.label} icon={dragItem.icon} />
                )}
              </>
            )}
          </div>
        </SortableContext>
      </div>
    </main>
  );
}

function DropGhost({ label, icon: Icon }: { label: string; icon?: FormFieldDefinition["icon"] }) {
  return (
    <div className="flex items-center gap-2 rounded-lg border-2 border-dashed border-primary/60 bg-primary/5 p-3 opacity-70 pointer-events-none select-none">
      {Icon ? (
        <Icon className="h-4 w-4 shrink-0 text-primary/60" />
      ) : (
        <div className="h-4 w-4 shrink-0 rounded bg-primary/20" />
      )}
      <span className="text-sm text-primary/70">{label}</span>
    </div>
  );
}

"use client";

import { Columns2, Columns3, GripVertical } from "lucide-react";
import { useDraggable } from "@dnd-kit/core";
import { cn } from "@/lib/utils";
import { BUILT_IN_LAYOUT_DEFS } from "../shared/built-in-layout-defs";
import type { FieldType, FormFieldDefinition } from "../form-renderer/types";

// ─── Draggable chip ───────────────────────────────────────────────────────────

interface FieldChipProps {
  draggableId: string;
  dragData: Record<string, unknown>;
  icon?: React.ComponentType<{ className?: string }>;
  label: string;
  onClick: () => void;
}

function FieldChip({ draggableId, dragData, icon: Icon, label, onClick }: FieldChipProps) {
  const { attributes, listeners, setNodeRef, isDragging } = useDraggable({
    id: draggableId,
    data: dragData,
  });

  return (
    <div
      ref={setNodeRef}
      className={cn(
        "flex items-center gap-1 w-full rounded-md border border-border bg-background",
        "text-sm transition-colors",
        isDragging && "opacity-40"
      )}
    >
      {/* Drag handle */}
      <button
        type="button"
        className="px-1.5 py-2 cursor-grab active:cursor-grabbing touch-none text-muted-foreground/40 hover:text-muted-foreground"
        {...attributes}
        {...listeners}
        aria-label="Drag to canvas"
      >
        <GripVertical className="h-3.5 w-3.5" />
      </button>

      {/* Click-to-add area */}
      <button
        type="button"
        onClick={onClick}
        className="flex items-center gap-2 flex-1 pr-3 py-2 text-left hover:text-accent-foreground cursor-pointer"
      >
        {Icon && <Icon className="h-3.5 w-3.5 shrink-0 text-muted-foreground" />}
        <span>{label}</span>
      </button>
    </div>
  );
}

// ─── Palette ──────────────────────────────────────────────────────────────────

interface FieldPaletteProps {
  catalog: FormFieldDefinition[];
  onAddField: (fieldType: FieldType) => void;
  onAddGrid: (columns: 2 | 3) => void;
}

export function FieldPalette({ catalog, onAddField, onAddGrid }: FieldPaletteProps) {
  const byCategory = catalog.reduce(
    (acc, def) => {
      if (!acc[def.category]) acc[def.category] = [];
      acc[def.category].push(def);
      return acc;
    },
    {} as Record<string, FormFieldDefinition[]>
  );

  return (
    <aside className="w-52 shrink-0 border-r border-border bg-muted/30 flex flex-col overflow-y-auto">
      <div className="px-3 py-3 border-b border-border">
        <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wide">Fields</p>
      </div>
      <div className="flex flex-col gap-4 p-3">
        {/* Layout */}
        <div>
          <p className="text-xs font-medium text-muted-foreground mb-1.5">Layout</p>
          <div className="flex flex-col gap-1">
            <FieldChip
              draggableId="palette:grid-2"
              dragData={{ source: "palette", kind: "grid", columns: 2 }}
              icon={Columns2}
              label="2 Columns"
              onClick={() => onAddGrid(2)}
            />
            <FieldChip
              draggableId="palette:grid-3"
              dragData={{ source: "palette", kind: "grid", columns: 3 }}
              icon={Columns3}
              label="3 Columns"
              onClick={() => onAddGrid(3)}
            />
            {BUILT_IN_LAYOUT_DEFS.map((def) => (
