export function FieldPreview({
  field,
  definition,
  isSelected,
  className,
  onSelect,
  onRemove,
  invisible,
}: FieldPreviewProps) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } =
    useSortable({ id: field.id });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
